#include <flat_map>
#include <print>
#include <string>
int main() {
    std::flat_map<std::string, int> scores;
    scores["Alice"] = 95;
    scores["Bob"] = 87;
    scores["Carol"] = 92;
    scores["Alice"] = 98;
    for (auto [name, score] : scores)
        std::println("{}: {}", name, score);
    std::println("contains Dave: {}", scores.contains("Dave"));
}

#include <flat_map>
#include <flat_set>
#include <print>
int main() {
    std::flat_set<int> nums;
    nums.insert(7);
    nums.insert(2);
    nums.insert(5);
    nums.insert(3);
    nums.insert(2); // duplicate ignored
    std::print("sorted:");
    for (int x : nums)
        std::print(" {}", x);
    std::println("");

    std::flat_map<int, std::string> m(
        std::sorted_unique,
        {{1, "one"}, {2, "two"}, {3, "three"}}
    );
    for (auto [k, v] : m)
        std::println("{} -> {}", k, v);
}

#include <flat_map>
#include <print>
#include <string>
#include <vector>
int main() {
    std::flat_map<std::string, int> config = {
        {"buffer_size", 4096}, {"max_conn", 100},
        {"port", 8080}, {"retries", 3}, {"timeout", 30}
    };
    for (const auto& key : {"port", "retries", "missing"}) {
        auto it = config.find(key);
        if (it != config.end())
            std::println("{} = {}", key, it->second);
        else
            std::println("{} not found", key);
    }
    // keys() returns a reference to the internal keys vector
    std::println("key count: {}", config.keys().size());
}
